classdef HeightSweepMemoryEstimator
    %HEIGHTSWEEPMEMORYESTIMATOR Preflight dense CPU memory requirements.
    %
    % Estimates tracked payload bytes for the current in-memory SGM, the
    % planned vectorized in-memory SGM, and the planned row-slab streamed SGM.
    % It deliberately excludes MATLAB headers, allocator fragmentation,
    % internal temporaries, source features, thread-pool state, and runtime
    % overhead. Image arrays use [rows,columns]; volumes use
    % [rows,columns,labels].
    %
    % Traceability: algo/main.tex Secs. 10.4, 11.2--11.4, and 14.6;
    % implementation plan Stages C0 and C3--C5.

    methods (Static)
        function report = estimate(imageSize, labelCount, options)
            arguments
                imageSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive}
                labelCount (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive}
                options.Precision (1, 1) string ...
                    {mustBeMember(options.Precision, ...
                    ["single", "double"])} = "single"
                options.Mode (1, 1) string ...
                    {mustBeMember(options.Mode, ...
                    ["current-in-memory", "optimized-in-memory", ...
                    "streamed"])} = "streamed"
                options.DirectionCount (1, 1) double ...
                    {mustBeMember(options.DirectionCount, [4, 8])} = 8
                options.RowSlabRows (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 128
                options.RecomputeBackwardCosts (1, 1) logical = true
                options.StorePathCosts (1, 1) logical = false
                options.Products (1, :) string ...
                    {mustBeNonempty, mustBeHeightSweepProducts} = ...
                    HeightSweepMemoryEstimator.productNames()
                options.MemoryBudgetGiB (1, 1) double ...
                    {mustBePositive} = Inf
            end

            nr = imageSize(1);
            nc = imageSize(2);
            n = prod(imageSize);
            nl = labelCount;
            valueBytes = HeightSweepMemoryEstimator.precisionBytes( ...
                options.Precision);
            volumeBytes = n .* nl .* valueBytes;
            slabRows = min(options.RowSlabRows, nr);
            slabBytes = slabRows .* nc .* nl .* valueBytes;
            boundaryDirectionCount = 1 + 2 .* (options.DirectionCount == 8);
            boundaryBytes = boundaryDirectionCount .* nc .* nl .* valueBytes;
            inMemoryScanlineStateBytes = 5 .* max(nr, nc) ...
                .* nl .* valueBytes;
            streamedScanlineStateBytes = 5 .* max(slabRows, nc) ...
                .* nl .* valueBytes;
            outputBytes = HeightSweepMemoryEstimator.outputBytes( ...
                n, nl, valueBytes, unique(options.Products, "stable"));

            currentWorkingBytes = 4 .* volumeBytes ...
                + n .* nl .* 8;
            if options.StorePathCosts
                currentWorkingBytes = currentWorkingBytes ...
                    + options.DirectionCount .* volumeBytes;
            end
            optimizedWorkingBytes = 2 .* volumeBytes ...
                + inMemoryScanlineStateBytes;
            if options.StorePathCosts
                optimizedWorkingBytes = optimizedWorkingBytes ...
                    + options.DirectionCount .* volumeBytes;
            end
            streamedWorkingBytes = 2 .* slabBytes + boundaryBytes ...
                + streamedScanlineStateBytes;
            persistentBytes = 0;
            switch options.Mode
                case "current-in-memory"
                    sgmWorkingBytes = currentWorkingBytes;
                case "optimized-in-memory"
                    sgmWorkingBytes = optimizedWorkingBytes;
                case "streamed"
                    sgmWorkingBytes = streamedWorkingBytes;
                    persistentBytes = volumeBytes;
                    if ~options.RecomputeBackwardCosts
                        persistentBytes = persistentBytes + volumeBytes;
                    end
            end

            requestedBytes = sgmWorkingBytes + outputBytes;
            budgetBytes = options.MemoryBudgetGiB .* 2 ^ 30;
            fits = requestedBytes <= budgetBytes;
            components = table( ...
                ["OneCostVolume"; "OneRowSlab"; "BoundaryStates"; ...
                "InMemoryScanlineStates"; ...
                "StreamedScanlineStates"; ...
                "SgmWorkingSet"; "RequestedOutputs"; ...
                "PersistentStore"; "RequestedRam"], ...
                [volumeBytes; slabBytes; boundaryBytes; ...
                inMemoryScanlineStateBytes; streamedScanlineStateBytes; ...
                sgmWorkingBytes; ...
                outputBytes; persistentBytes; requestedBytes], ...
                VariableNames=["Component", "Bytes"]);
            components.Gibibytes = components.Bytes ./ 2 ^ 30;
            report = struct( ...
                "ImageSize", imageSize, ...
                "PixelCount", n, ...
                "LabelCount", nl, ...
                "Precision", options.Precision, ...
                "BytesPerCost", valueBytes, ...
                "Mode", options.Mode, ...
                "DirectionCount", options.DirectionCount, ...
                "RowSlabRows", slabRows, ...
                "BoundaryDirectionCount", boundaryDirectionCount, ...
                "RecomputeBackwardCosts", ...
                options.RecomputeBackwardCosts, ...
                "StorePathCosts", options.StorePathCosts, ...
                "Products", unique(options.Products, "stable"), ...
                "OneCostVolumeBytes", volumeBytes, ...
                "OneRowSlabBytes", slabBytes, ...
                "BoundaryStateBytes", boundaryBytes, ...
                "InMemoryScanlineStateBytes", ...
                inMemoryScanlineStateBytes, ...
                "StreamedScanlineStateBytes", ...
                streamedScanlineStateBytes, ...
                "SgmWorkingBytes", sgmWorkingBytes, ...
                "OutputBytes", outputBytes, ...
                "PersistentStoreBytes", persistentBytes, ...
                "RequestedRamBytes", requestedBytes, ...
                "MemoryBudgetGiB", options.MemoryBudgetGiB, ...
                "FitsMemoryBudget", fits, ...
                "Components", components, ...
                "Definition", ...
                "tracked payload lower bound; excludes features, temporaries, MATLAB/runtime overhead");

            if ~fits
                error("HeightSweepMemoryEstimator:BudgetExceeded", ...
                    "Estimated tracked RAM is %.3f GiB, exceeding the " ...
                    + "configured %.3f GiB budget. Reduce slab rows, labels, " ...
                    + "or requested products.", ...
                    requestedBytes ./ 2 ^ 30, options.MemoryBudgetGiB);
            end
        end

        function report = estimateAdaptive(initialPlan, finalPlan, options)
            %ESTIMATEADAPTIVE Preflight persistent local-label hierarchy.
            %
            % RAM is the maximum of dense generation and streamed SGM stage
            % peaks. Disk contains the final variable-label cost and aggregate
            % stores. Expansion work reevaluates every changed tile in full.
            % Traceability: algo/main.tex Secs. 10.4 and 14.6;
            % implementation plan C1 milestones 5--6.
            arguments
                initialPlan table {mustBeAdaptivePreflightPlan}
                finalPlan table ...
                    {mustBeAdaptivePreflightPlan, ...
                    mustMatchAdaptivePreflightPlan(finalPlan, initialPlan)}
                options.Precision (1, 1) string ...
                    {mustBeMember(options.Precision, ...
                    ["single", "double"])} = "single"
                options.DirectionCount (1, 1) double ...
                    {mustBeMember(options.DirectionCount, [4, 8])} = 8
                options.IntegrationRadius (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 3
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.GroupIdenticalBands (1, 1) logical = false
                options.MaximumBandTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 4
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 1
                options.PyramidFactors (1, :) double ...
                    {mustBeAdaptivePyramidFactors} = 1
                options.OutputProfile (1, 1) string ...
                    {mustBeMember(options.OutputProfile, ...
                    ["diagnostic", "compact"])} = "diagnostic"
                options.MemoryBudgetGiB (1, 1) double ...
                    {mustBePositive} = Inf
                options.DiskBudgetGiB (1, 1) double ...
                    {mustBePositive} = Inf
                options.RamSafetyFactor (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.RamSafetyFactor, 1)} = 1.25
                options.DiskSafetyFactor (1, 1) double ...
                    {mustBeFinite, mustBeGreaterThanOrEqual( ...
                    options.DiskSafetyFactor, 1)} = 1.1
                options.MeasuredDensePixelLabelsPerSecond (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0
                options.MeasuredSgmPixelLabelsPerSecond (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0
                options.MeasuredFileIoMebibytesPerSecond (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0
                options.RefuseUnsafe (1, 1) logical = true
            end

            valueBytes = HeightSweepMemoryEstimator.precisionBytes( ...
                options.Precision);
            nr = max(finalPlan.RowEnd);
            nc = max(finalPlan.ColumnEnd);
            imageSize = [nr, nc];
            n = prod(imageSize);
            changed = finalPlan.LabelCount ~= initialPlan.LabelCount ...
                | ~cellfun(@isequal, finalPlan.HeightLabelsMetres, ...
                initialPlan.HeightLabelsMetres);
            initialPixelLabels = sum( ...
                initialPlan.PixelCount .* initialPlan.LabelCount);
            expansionPixelLabels = sum( ...
                finalPlan.PixelCount(changed) ...
                .* finalPlan.LabelCount(changed));
            evaluatedPixelLabels = ...
                initialPixelLabels + expansionPixelLabels;
            finalPixelLabels = sum( ...
                finalPlan.PixelCount .* finalPlan.LabelCount);

            initialBands = HeightSweepMemoryEstimator.adaptiveBands( ...
                initialPlan, options.GroupIdenticalBands, ...
                options.MaximumBandTiles);
            if any(changed)
                expansionBands = HeightSweepMemoryEstimator.adaptiveBands( ...
                    finalPlan(changed, :), options.GroupIdenticalBands, ...
                    options.MaximumBandTiles);
            else
                expansionBands = cell(0, 1);
            end
            bands = [initialBands; expansionBands];
            scratch = zeros(numel(bands), 1);
            returned = zeros(numel(bands), 1);
            corePixels = zeros(numel(bands), 1);
            extendedPixels = zeros(numel(bands), 1);
            for k = 1:numel(bands)
                ids = bands{k};
                if k <= numel(initialBands)
                    p = initialPlan;
                else
                    p = finalPlan(changed, :);
                end
                b = [min(p.RowStart(ids)), max(p.RowEnd(ids)), ...
                    min(p.ColumnStart(ids)), max(p.ColumnEnd(ids))];
                rows = b(2) - b(1) + 1;
                columns = b(4) - b(3) + 1;
                nl = p.LabelCount(ids(1));
                [scratch(k), returned(k), corePixels(k), ...
                    extendedPixels(k)] = ...
                    HeightSweepMemoryEstimator.adaptiveBandBytes( ...
                    rows, columns, nl, options.IntegrationRadius, ...
                    options.LabelBlockSize, valueBytes);
            end
            pending = min(options.MaximumPendingTiles, numel(bands));
            threadPrivateBytes = pending .* max(scratch);
            sortedReturned = sort(returned, "descend");
            pendingResultBytes = sum(sortedReturned(1:pending));

            rowBounds = unique( ...
                [finalPlan.RowStart, finalPlan.RowEnd], "rows", "sorted");
            rowCostBytes = zeros(size(rowBounds, 1), 1);
            rowStateEntries = zeros(size(rowBounds, 1), 1);
            for k = 1:size(rowBounds, 1)
                ids = find(finalPlan.RowStart == rowBounds(k, 1) ...
                    & finalPlan.RowEnd == rowBounds(k, 2));
                rowCostBytes(k) = sum(finalPlan.PixelCount(ids) ...
                    .* finalPlan.LabelCount(ids)) .* valueBytes;
                widths = finalPlan.ColumnEnd(ids) ...
                    - finalPlan.ColumnStart(ids) + 1;
                rowStateEntries(k) = sum( ...
                    widths .* finalPlan.LabelCount(ids));
            end
            maximumRowCostBytes = max(rowCostBytes);
            sgmRowGroupBytes = 2 .* maximumRowCostBytes;
            stateDirections = 2 .* (1 + 2 .* (options.DirectionCount == 8));
            sgmScanlineStateBytes = stateDirections ...
                .* max(rowStateEntries) .* (valueBytes + 8);

            pyramidBytes = 0;
            for factor = options.PyramidFactors
                levelPixels = prod(ceil(imageSize ./ factor));
                pyramidBytes = pyramidBytes ...
                    + levelPixels .* (2 .* valueBytes + 2);
            end
            inheritedPlanBytes = 40 .* n;
            [rawOutputBytes, refinedOutputBytes, sgmOutputBytes, ...
                warningOutputBytes] = ...
                HeightSweepMemoryEstimator.adaptiveOutputBytes( ...
                n, valueBytes, options.OutputProfile);
            if options.OutputProfile == "compact"
                outputBytes = inheritedPlanBytes + sgmOutputBytes;
                denseStageOutputBytes = ...
                    inheritedPlanBytes + rawOutputBytes;
                sgmStageOutputBytes = ...
                    inheritedPlanBytes + sgmOutputBytes;
                outputProfile = ...
                    "compact SGM height/validity/correspondence/margin";
            else
                outputBytes = inheritedPlanBytes + rawOutputBytes ...
                    + refinedOutputBytes + sgmOutputBytes ...
                    + warningOutputBytes;
                denseStageOutputBytes = outputBytes;
                sgmStageOutputBytes = outputBytes;
                outputProfile = ...
                    "current runFineAdaptive diagnostic result";
            end
            denseStageBytes = pyramidBytes + denseStageOutputBytes ...
                + threadPrivateBytes + pendingResultBytes;
            sgmStageBytes = pyramidBytes + sgmStageOutputBytes ...
                + sgmRowGroupBytes + sgmScanlineStateBytes;
            trackedPeakRamBytes = max(denseStageBytes, sgmStageBytes);
            requestedRamBytes = ...
                options.RamSafetyFactor .* trackedPeakRamBytes;
            ramSafetyReserveBytes = requestedRamBytes - trackedPeakRamBytes;
            costStoreBytes = finalPixelLabels .* valueBytes;
            aggregateStoreBytes = costStoreBytes;
            persistentStoreBytes = costStoreBytes + aggregateStoreBytes;
            requestedDiskBytes = ...
                options.DiskSafetyFactor .* persistentStoreBytes;
            diskSafetyReserveBytes = ...
                requestedDiskBytes - persistentStoreBytes;
            ioBytes = (initialPixelLabels + expansionPixelLabels ...
                + 5 .* finalPixelLabels) .* valueBytes;

            denseSeconds = HeightSweepMemoryEstimator.rateSeconds( ...
                evaluatedPixelLabels, ...
                options.MeasuredDensePixelLabelsPerSecond);
            sgmSeconds = HeightSweepMemoryEstimator.rateSeconds( ...
                finalPixelLabels, ...
                options.MeasuredSgmPixelLabelsPerSecond);
            ioSeconds = HeightSweepMemoryEstimator.rateSeconds( ...
                ioBytes ./ 2 ^ 20, ...
                options.MeasuredFileIoMebibytesPerSecond);
            estimatedTotalSeconds = HeightSweepMemoryEstimator.sumRates( ...
                [denseSeconds, sgmSeconds, ioSeconds]);
            memoryBudgetBytes = options.MemoryBudgetGiB .* 2 ^ 30;
            diskBudgetBytes = options.DiskBudgetGiB .* 2 ^ 30;
            fitsMemory = requestedRamBytes <= memoryBudgetBytes;
            fitsDisk = requestedDiskBytes <= diskBudgetBytes;
            components = table( ...
                ["PyramidImagesAndMasks"; "InheritedFinePlanMaps"; ...
                "RawAdaptiveOutputs"; "RefinedOutputs"; ...
                "StreamedSgmOutputs"; "WarningOutputs"; ...
                "ThreadPrivateScratch"; "PendingBandResults"; ...
                "SgmCostAndAggregateRow"; "SgmPathScanlines"; ...
                "DenseStageRam"; "SgmStageRam"; "TrackedPeakRam"; ...
                "RamSafetyReserve"; "RequestedRam"; "CostStore"; ...
                "AggregateStore"; "PersistentStores"; ...
                "DiskSafetyReserve"; "RequestedDisk"], ...
                [pyramidBytes; inheritedPlanBytes; rawOutputBytes; ...
                refinedOutputBytes; sgmOutputBytes; warningOutputBytes; ...
                threadPrivateBytes; pendingResultBytes; ...
                sgmRowGroupBytes; sgmScanlineStateBytes; ...
                denseStageBytes; sgmStageBytes; trackedPeakRamBytes; ...
                ramSafetyReserveBytes; requestedRamBytes; costStoreBytes; ...
                aggregateStoreBytes; persistentStoreBytes; ...
                diskSafetyReserveBytes; requestedDiskBytes], ...
                VariableNames=["Component", "Bytes"]);
            components.Gibibytes = components.Bytes ./ 2 ^ 30;
            report = struct( ...
                "ImageSize", imageSize, ...
                "PixelCount", n, ...
                "Precision", options.Precision, ...
                "BytesPerCost", valueBytes, ...
                "InitialTileCount", height(initialPlan), ...
                "ExpandedTileCount", nnz(changed), ...
                "InitialBandCount", numel(initialBands), ...
                "ExpansionBandCount", numel(expansionBands), ...
                "MaximumBandTileCount", max(cellfun(@numel, bands)), ...
                "MaximumBandCorePixels", max(corePixels), ...
                "MaximumBandExtendedPixels", max(extendedPixels), ...
                "MaximumPendingBands", pending, ...
                "InitialPixelLabelCount", initialPixelLabels, ...
                "ExpansionPixelLabelCount", expansionPixelLabels, ...
                "EvaluatedPixelLabelCount", evaluatedPixelLabels, ...
                "FinalStoredPixelLabelCount", finalPixelLabels, ...
                "MinimumFinalLabelCount", min(finalPlan.LabelCount), ...
                "MedianFinalLabelCount", median(finalPlan.LabelCount), ...
                "MaximumFinalLabelCount", max(finalPlan.LabelCount), ...
                "PyramidFactors", options.PyramidFactors, ...
                "PyramidBytes", pyramidBytes, ...
                "OutputProfile", outputProfile, ...
                "OutputBytes", outputBytes, ...
                "MaximumWorkerScratchBytes", max(scratch), ...
                "ThreadPrivateScratchBytes", threadPrivateBytes, ...
                "PendingResultBytes", pendingResultBytes, ...
                "MaximumRowCostBytes", maximumRowCostBytes, ...
                "SgmRowGroupBytes", sgmRowGroupBytes, ...
                "SgmScanlineStateBytes", sgmScanlineStateBytes, ...
                "DenseStageRamBytes", denseStageBytes, ...
                "SgmStageRamBytes", sgmStageBytes, ...
                "TrackedPeakRamBytes", trackedPeakRamBytes, ...
                "RamSafetyFactor", options.RamSafetyFactor, ...
                "RamSafetyReserveBytes", ramSafetyReserveBytes, ...
                "RequestedRamBytes", requestedRamBytes, ...
                "CostStoreBytes", costStoreBytes, ...
                "AggregateStoreBytes", aggregateStoreBytes, ...
                "PersistentStoreBytes", persistentStoreBytes, ...
                "DiskSafetyFactor", options.DiskSafetyFactor, ...
                "DiskSafetyReserveBytes", diskSafetyReserveBytes, ...
                "RequestedDiskBytes", requestedDiskBytes, ...
                "EstimatedIoBytes", ioBytes, ...
                "EstimatedDenseSeconds", denseSeconds, ...
                "EstimatedSgmSeconds", sgmSeconds, ...
                "EstimatedIoSeconds", ioSeconds, ...
                "EstimatedTotalSeconds", estimatedTotalSeconds, ...
                "MemoryBudgetGiB", options.MemoryBudgetGiB, ...
                "DiskBudgetGiB", options.DiskBudgetGiB, ...
                "FitsMemoryBudget", fitsMemory, ...
                "FitsDiskBudget", fitsDisk, ...
                "SafeToRun", fitsMemory && fitsDisk, ...
                "Components", components, ...
                "Definition", ...
                "conservative tracked payload; includes current adaptive " ...
                + options.OutputProfile + " outputs, pyramid images/masks, " ...
                + "bounded worker " ...
                + "scratch, row-of-tiles SGM, and two persistent stores; " ...
                + "explicit RAM/disk safety factors cover untracked overhead; " ...
                + "raw component values exclude MATLAB headers, allocator " ...
                + "fragmentation, camera internals, source-file I/O, and " ...
                + "OS/thread-pool overhead");
            if options.RefuseUnsafe && ~fitsMemory
                error("HeightSweepMemoryEstimator:AdaptiveRamBudgetExceeded", ...
                    "Adaptive preflight requests %.3f GiB RAM, exceeding " ...
                    + "the configured %.3f GiB. Reduce outputs, pending/band " ...
                    + "limits, labels, or image size.", ...
                    requestedRamBytes ./ 2 ^ 30, options.MemoryBudgetGiB);
            elseif options.RefuseUnsafe && ~fitsDisk
                error("HeightSweepMemoryEstimator:AdaptiveDiskBudgetExceeded", ...
                    "Adaptive preflight requests %.3f GiB persistent " ...
                    + "storage, exceeding the configured %.3f GiB.", ...
                    requestedDiskBytes ./ 2 ^ 30, options.DiskBudgetGiB);
            end
        end
    end

    methods (Static, Access = private)
        function names = productNames()
            names = ["Height", "Validity", "LabelIndex", "BestCost", ...
                "SecondBestCost", "NeighborCosts", "Margin", ...
                "Curvature", "ValidLabelCount", "Observability", ...
                "Correspondence"];
        end

        function bytes = precisionBytes(precision)
            if precision == "single"
                bytes = 4;
            else
                bytes = 8;
            end
        end

        function bytes = outputBytes(n, labelCount, valueBytes, products)
            bytes = 0;
            indexBytes = 2 + 2 .* (labelCount > intmax("uint16"));
            for k = 1:numel(products)
                switch products(k)
                    case "Height"
                        bytes = bytes + 8 .* n;
                    case "Validity"
                        bytes = bytes + n;
                    case "LabelIndex"
                        bytes = bytes + indexBytes .* n;
                    case {"BestCost", "SecondBestCost", "Margin", ...
                            "Curvature"}
                        bytes = bytes + valueBytes .* n;
                    case "NeighborCosts"
                        bytes = bytes + 2 .* valueBytes .* n;
                    case "ValidLabelCount"
                        bytes = bytes + indexBytes .* n;
                    case "Observability"
                        bytes = bytes + 8 .* n;
                    case "Correspondence"
                        bytes = bytes + 16 .* n;
                end
            end
        end

        function groups = adaptiveBands(plan, enabled, maximumTiles)
            if ~enabled
                groups = arrayfun(@(k) k, (1:height(plan)).', ...
                    UniformOutput=false);
                return
            end
            rowBounds = unique( ...
                [plan.RowStart, plan.RowEnd], "rows", "sorted");
            groups = cell(0, 1);
            for r = 1:size(rowBounds, 1)
                ids = find(plan.RowStart == rowBounds(r, 1) ...
                    & plan.RowEnd == rowBounds(r, 2));
                [~, order] = sort(plan.ColumnStart(ids));
                ids = reshape(ids(order), 1, []);
                current = ids(1);
                for k = 2:numel(ids)
                    previous = current(end);
                    id = ids(k);
                    if plan.ColumnEnd(previous) + 1 ...
                            == plan.ColumnStart(id) ...
                            && isequal( ...
                            plan.HeightLabelsMetres{previous}, ...
                            plan.HeightLabelsMetres{id}) ...
                            && numel(current) < maximumTiles
                        current(end + 1) = id; %#ok<AGROW>
                    else
                        groups{end + 1, 1} = current; %#ok<AGROW>
                        current = id;
                    end
                end
                groups{end + 1, 1} = current; %#ok<AGROW>
            end
        end

        function [scratch, returned, corePixels, extendedPixels] = ...
                adaptiveBandBytes(rows, columns, labelCount, radius, ...
                labelBlockSize, valueBytes)
            corePixels = rows .* columns;
            extendedPixels = (rows + 2 .* radius) ...
                .* (columns + 2 .* radius);
            block = min(labelBlockSize, labelCount);
            p = 2 .* extendedPixels .* 8;
            geometry = extendedPixels .* block .* (5 .* 8);
            intensity = extendedPixels .* valueBytes ...
                + extendedPixels .* block .* valueBytes;
            masks = extendedPixels ...
                + 3 .* extendedPixels .* block;
            blockCosts = 2 .* corePixels .* block .* valueBytes;
            state = corePixels .* (6 .* valueBytes + 32);
            costResult = corePixels .* labelCount .* valueBytes;
            summary = corePixels .* (25 + 6 .* valueBytes);
            returned = costResult + summary;
            scratch = p + geometry + intensity + masks ...
                + blockCosts + state + costResult + summary;
        end

        function [raw, refined, sgm, warning] = ...
                adaptiveOutputBytes(n, valueBytes, profile)
            if profile == "compact"
                % Mandatory/trigger result plus internal coverage and
                % projection-valid working masks while the dense call returns.
                raw = 44 .* n;
                refined = 0;
                % Returned height/validity/correspondence/margin plus the
                % pre-compaction selected height and projection work arrays.
                sgm = n .* (34 + valueBytes);
                warning = 0;
            else
                raw = n .* (77 + 6 .* valueBytes);
                refined = 61 .* n;
                sgm = n .* (57 + 6 .* valueBytes);
                warning = 17 .* n;
            end
        end

        function seconds = rateSeconds(count, rate)
            if rate > 0
                seconds = count ./ rate;
            else
                seconds = NaN;
            end
        end

        function total = sumRates(seconds)
            if any(isnan(seconds))
                total = NaN;
            else
                total = sum(seconds);
            end
        end
    end
end

function mustBeHeightSweepProducts(products)
names = ["Height", "Validity", "LabelIndex", "BestCost", ...
    "SecondBestCost", "NeighborCosts", "Margin", "Curvature", ...
    "ValidLabelCount", "Observability", "Correspondence"];
mustBeMember(products, names);
end

function mustBeAdaptivePreflightPlan(plan)
required = ["Tile", "RowStart", "RowEnd", "ColumnStart", ...
    "ColumnEnd", "PixelCount", "LabelCount", "HeightLabelsMetres"];
if isempty(plan) || ~all(ismember( ...
        required, string(plan.Properties.VariableNames)))
    error("HeightSweepMemoryEstimator:InvalidAdaptivePlan", ...
        "Adaptive plans must contain tile bounds, counts, and label vectors.");
end
integerValues = [plan.Tile; plan.RowStart; plan.RowEnd; ...
    plan.ColumnStart; plan.ColumnEnd; plan.PixelCount; plan.LabelCount];
if any(~isfinite(integerValues)) || any(integerValues < 1) ...
        || any(integerValues ~= fix(integerValues)) ...
        || any(plan.PixelCount ~= (plan.RowEnd - plan.RowStart + 1) ...
        .* (plan.ColumnEnd - plan.ColumnStart + 1)) ...
        || ~iscell(plan.HeightLabelsMetres) ...
        || any(cellfun(@(z) ~isa(z, "double") || ~isrow(z) ...
        || numel(z) < 3 || any(~isfinite(z)) ...
        || any(diff(z) <= 0), plan.HeightLabelsMetres)) ...
        || any(cellfun(@numel, plan.HeightLabelsMetres) ~= plan.LabelCount)
    error("HeightSweepMemoryEstimator:InvalidAdaptivePlan", ...
        "Adaptive plan bounds, counts, and labels must be finite and valid.");
end
rowBounds = unique([plan.RowStart, plan.RowEnd], "rows", "sorted");
nr = max(plan.RowEnd);
nc = max(plan.ColumnEnd);
if rowBounds(1, 1) ~= 1 || rowBounds(end, 2) ~= nr ...
        || any(rowBounds(2:end, 1) ~= rowBounds(1:(end - 1), 2) + 1)
    error("HeightSweepMemoryEstimator:IncompleteAdaptivePlan", ...
        "Adaptive tile rows must partition the image.");
end
for k = 1:size(rowBounds, 1)
    ids = find(plan.RowStart == rowBounds(k, 1) ...
        & plan.RowEnd == rowBounds(k, 2));
    [starts, order] = sort(plan.ColumnStart(ids));
    ends = plan.ColumnEnd(ids(order));
    if starts(1) ~= 1 || ends(end) ~= nc ...
            || any(starts(2:end) ~= ends(1:(end - 1)) + 1)
        error("HeightSweepMemoryEstimator:IncompleteAdaptivePlan", ...
            "Every adaptive tile row must partition all columns.");
    end
end
end

function mustMatchAdaptivePreflightPlan(finalPlan, initialPlan)
spatial = ["Tile", "RowStart", "RowEnd", "ColumnStart", ...
    "ColumnEnd", "PixelCount"];
if height(finalPlan) ~= height(initialPlan) ...
        || ~isequal(finalPlan(:, spatial), initialPlan(:, spatial))
    error("HeightSweepMemoryEstimator:AdaptivePlanSpatialMismatch", ...
        "Initial and final plans must preserve spatial tile identity.");
end
end

function mustBeAdaptivePyramidFactors(factors)
if any(factors ~= fix(factors)) || factors(end) ~= 1 ...
        || any(diff(factors) >= 0)
    error("HeightSweepMemoryEstimator:InvalidPyramidFactors", ...
        "PyramidFactors must be descending positive integers ending at one.");
end
end
